package com.restaurantcraft.block; import com.restaurantcraft.blockentity.SinkBlockEntity; import net.minecraft.core.BlockPos; import net.minecraft.server.level.ServerPlayer; import net.minecraft.world.*; import net.minecraft.world.entity.player.Player; import net.minecraft.world.level.*; import net.minecraft.world.level.block.*; import net.minecraft.world.level.block.entity.*; import net.minecraft.world.level.block.state.BlockState; import net.minecraft.world.phys.BlockHitResult; import org.jetbrains.annotations.Nullable; public class SinkBlock extends BaseEntityBlock { public SinkBlock(Properties p){super(p);} public RenderShape getRenderShape(BlockState s){return RenderShape.MODEL;} @Nullable public BlockEntity newBlockEntity(BlockPos p, BlockState s){return new SinkBlockEntity(p,s);} @Nullable public <T extends BlockEntity> BlockEntityTicker<T> getTicker(Level l, BlockState s, BlockEntityType<T> t){return l.isClientSide?null:(lvl,pos,st,be)->{if(be instanceof SinkBlockEntity sink)sink.tick();};} public InteractionResult use(BlockState s, Level l, BlockPos p, Player player, InteractionHand h, BlockHitResult hit){ if(!l.isClientSide && l.getBlockEntity(p) instanceof SinkBlockEntity be && player instanceof ServerPlayer sp) be.openMenu(sp); return InteractionResult.sidedSuccess(l.isClientSide);} }